script.js:
var screen = document.getElementById("screen");

function toggleTV() {
	screen.classList.toggle("animate");
}

style.css:
* {
	margin: 0;
	padding: 0;
	box-sizing: border-box;
}

body,
html {
	height: 100%;
	width: 100%;
	overflow: hidden;
	background-color: black;
}

.filter {
	top: 0;
	left: 0;
	position: absolute;
	display: block;
	height: 100vh;
	width: 100vw;

	z-index: 999999999;
	mix-blend-mode: multiply;
}
#screen {
	height: 100vh;
	background-color:red;
	overflow:hidden;
}

.palette-container {
	filter: url(#scanline-displacement);
	display: flex;
	flex-direction: row;
	height: 90vh;
	width: 100%;
	margin-top: -10px;
	transition: all 1s ease;
}

.palette-container-2 {
	filter: url(#scanline-displacement);
	display: flex;
	flex-direction: row;
	margin-top: -10px;
	height: calc(10vh + 20px);
	width: 100%;
}
.color-swatch {
	flex: 1;
	transition: flex 0.3s ease;
	border: 0px solid black;
}

.animate {
	animation: turnTheTVOff 2s ease;
	animation-fill-mode: forwards;
}

